modelBuilder.Entity<ServerMember>()
.HasKey(sm => new { sm.ServerId, sm.ProfileId });
modelBuilder.Entity<ServerMember>()
.HasOne(sm => sm.Server)
.WithMany(s => s.Members)
.HasForeignKey(sm => sm.ServerId);
modelBuilder.Entity(ServerMember)
.HasOne(sm => sm.Profile)
.WithMany(p => p.Servers)
.HasForeignKey(sm => sm.ProfileId);
-----------------------------------------------------------------
modelBuilder.Entity<ServerMember>()
.HasIndex(sm => sm.ProfileId);
modelBuilder.Entity<ServerMember>()
.HasIndex(sm => sm.PrimaryPlayerId);
